// Combine all data into a daily briefing
const dashboard = $('Fetch Command Center').first().json;
const drafts = $('Fetch Pending Drafts').first().json || [];
const gaps = $('Fetch Market Gaps').first().json || [];

const tasks = (dashboard.tasks || []).sort((a, b) => b.priority_score - a.priority_score);
const top3 = tasks.slice(0, 3);
const suggestions = (dashboard.suggestions || []).slice(0, 3);
const briefing = (dashboard.briefing || []).slice(0, 3);
const goals = dashboard.goals_week || [];

// Format top 3 tasks for WhatsApp
const whatsappMsg = `*Daily Focus — ${new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'short', day: 'numeric'})}*\n\n` +
  top3.map((t, i) => `${i+1}. *${t.title}*\n   ${t.why || ''}\n   _${t.estimated_minutes}min · ${t.project_tag}_`).join('\n\n') +
  `\n\n---\nReply: "done 1" to complete, "add [task]" to add`;

// Format email HTML
const taskRows = tasks.map(t => 
  `<tr><td style="padding:8px;border-bottom:1px solid #222">${t.title}</td><td style="padding:8px;text-align:center;border-bottom:1px solid #222">${t.priority_score.toFixed(1)}</td><td style="padding:8px;text-align:center;border-bottom:1px solid #222">${t.estimated_minutes}m</td></tr>`
).join('');

const draftRows = (Array.isArray(drafts) ? drafts : []).slice(0, 5).map(d =>
  `<li><strong>${d.title}</strong> (${d.platform}) — hook score: ${d.hook_score ? Math.round(d.hook_score * 100) + '%' : 'N/A'}</li>`
).join('');

const gapRows = (Array.isArray(gaps) ? gaps : []).slice(0, 3).map(g =>
  `<li><strong>${g.description.slice(0, 80)}...</strong><br><em>${g.suggested_action || ''}</em></li>`
).join('');

const goalRows = goals.map(g =>
  `<li>${g.title} — ${Math.round(g.progress * 100)}%</li>`
).join('');

const emailHtml = `
<div style="font-family:-apple-system,sans-serif;max-width:600px;margin:0 auto;background:#0A0A0B;color:#E4E4E7;padding:32px;border-radius:16px">
  <h1 style="color:#A855F7;font-size:24px;margin-bottom:4px">Operator Dashboard</h1>
  <p style="color:#6A6A80;margin-bottom:24px">${new Date().toLocaleDateString('en-US', {weekday: 'long', month: 'long', day: 'numeric', year: 'numeric'})}</p>

  <h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px">Priority Tasks (${tasks.length})</h2>
  <table style="width:100%;border-collapse:collapse;margin-bottom:24px">
    <tr style="color:#6A6A80;font-size:12px"><th style="text-align:left;padding:8px">Task</th><th style="padding:8px">Score</th><th style="padding:8px">Time</th></tr>
    ${taskRows}
  </table>

  <h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px">Weekly Goals</h2>
  <ul style="color:#9494AD;margin-bottom:24px">${goalRows || '<li>No goals set</li>'}</ul>

  <h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px">Content Drafts to Review (${Array.isArray(drafts) ? drafts.length : 0})</h2>
  <ul style="color:#9494AD;margin-bottom:24px">${draftRows || '<li>No pending drafts</li>'}</ul>

  <h2 style="color:#E4E4E7;font-size:16px;border-bottom:1px solid #222;padding-bottom:8px">Market Opportunities</h2>
  <ul style="color:#9494AD;margin-bottom:24px">${gapRows || '<li>No new gaps</li>'}</ul>

  <p style="color:#6A6A80;font-size:12px;margin-top:32px;text-align:center">Generated by Operator Dashboard AI</p>
</div>`;

return [{
  json: {
    whatsappMessage: whatsappMsg,
    emailHtml: emailHtml,
    emailSubject: `Operator Briefing — ${new Date().toLocaleDateString('en-US', {month: 'short', day: 'numeric'})}`,
    top3Tasks: top3,
    taskCount: tasks.length,
    draftCount: Array.isArray(drafts) ? drafts.length : 0,
    gapCount: Array.isArray(gaps) ? gaps.length : 0
  }
}];
